1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const FIXED_FEE = 5;
12	const ALIKE_COMPONENT_BLOCK_SIZE = 3;
13	const ALIKE_COMPONENT_BLOCK_PRICE = 60;
14	
15	function applyFirstInsuranceSurcharge(amount: number): number {
16	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
17	}
18	
19	function countByType(items: { type: string }[]): Record<string, number> {
20	  return items.reduce<Record<string, number>>((counts, item) => {
21	    counts[item.type] = (counts[item.type] ?? 0) + 1;
22	    return counts;
23	  }, {});
24	}
25	
26	function priceForType(type: string, count: number): number {
27	  const blocks = Math.floor(count / ALIKE_COMPONENT_BLOCK_SIZE);
28	  const leftover = count % ALIKE_COMPONENT_BLOCK_SIZE;
29	  return blocks * ALIKE_COMPONENT_BLOCK_PRICE + leftover * BASE_PRICES[type];
30	}
31	
32	function quoteBasePrice(items: { type: string }[]): number {
33	  const counts = countByType(items);
34	  return Object.entries(counts).reduce(
35	    (total, [type, count]) => total + priceForType(type, count),
36	    0
37	  );
38	}
39	
40	function applyRatioIf(
41	  condition: boolean,
42	  basePrice: number,
43	  numerator: number,
44	  denominator: number
45	): number {
46	  return condition ? (basePrice * numerator) / denominator : basePrice;
47	}
48	
49	function applyCursedSurcharge(items: { cursed: boolean }[], basePrice: number): number {
50	  const hasCursed = items.some((item) => item.cursed);
51	  return applyRatioIf(hasCursed, basePrice, 3, 2);
52	}
53	
54	function applyEnchantedSurcharge(items: { enchantment: number }[], basePrice: number): number {
55	  const hasHighEnchant = items.some((item) => item.enchantment >= 5);
56	  return applyRatioIf(hasHighEnchant, basePrice, 13, 10);
57	}
58	
59	function applyLoyaltyDiscount(yearsWithMHPCO: number, basePrice: number): number {
60	  return applyRatioIf(yearsWithMHPCO >= 2, basePrice, 8, 10);
61	}
62	
63	export function runScenario(scenario: any): unknown {
64	  const items = scenario.steps[0].items;
65	  const basePrice = quoteBasePrice(items);
66	  const withCursed = applyCursedSurcharge(items, basePrice);
67	  const withEnchanted = applyEnchantedSurcharge(items, withCursed);
68	  const withLoyalty = applyLoyaltyDiscount(scenario.customer.yearsWithMHPCO, withEnchanted);
69	  const premium = applyFirstInsuranceSurcharge(withLoyalty) + FIXED_FEE;
70	  return { results: [{ premium }] };
71	}
